# @cctt_verify {"v":2,"sym":"sympy.tensor.tensor.components_canon_args","kind":"function","src_hash":"e0c7cbdea8b4798d","in":{"base":"Any"},"out":{"base":"Any"},"spec":{"lhs":"components_canon_args(com)","rhs":"components_canon_args produces the expected output","over":{"base":"Any"},"name":"components_canon_args_correct"},"guarantee":"components_canon_args produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.tensor.tensor.components_canon_args_correct","statement":"Path(components_canon_args(x), components_canon_args produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"f4e048fde6e7788e"}
def components_canon_args(components):
    numtyp = []
    prev = None
    for t in components:
        if t == prev:
            numtyp[-1][1] += 1
        else:
            prev = t
            numtyp.append([prev, 1])
    v = []
    for h, n in numtyp:
        if h.comm in (0, 1):
            comm = h.comm
        else:
            comm = TensorManager.get_comm(h.comm, h.comm)
        v.append((h.symmetry.base, h.symmetry.generators, n, comm))
    return v


