# @cctt_verify {"v":2,"sym":"sympy.tensor.tensor.riemann_cyclic_replace","kind":"function","src_hash":"55448557d4bf14b1","in":{"base":"Any"},"out":{"base":"Any"},"spec":{"lhs":"riemann_cyclic_replace(t_r)","rhs":"replace riemann tensor with an equivalent expression","over":{"base":"Any"},"name":"riemann_cyclic_replace_correct"},"guarantee":"replace riemann tensor with an equivalent expression","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.tensor.tensor.riemann_cyclic_replace_correct","statement":"Path(riemann_cyclic_replace(x), replace riemann tensor with an equivalent expression)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"befe13e343e59274"}
def riemann_cyclic_replace(t_r):
    """
    replace Riemann tensor with an equivalent expression

    ``R(m,n,p,q) -> 2/3*R(m,n,p,q) - 1/3*R(m,q,n,p) + 1/3*R(m,p,n,q)``

    """
    free = sorted(t_r.free, key=lambda x: x[1])
    m, n, p, q = [x[0] for x in free]
    t0 = t_r*Rational(2, 3)
    t1 = -t_r.substitute_indices((m,m),(n,q),(p,n),(q,p))*Rational(1, 3)
    t2 = t_r.substitute_indices((m,m),(n,p),(p,n),(q,q))*Rational(1, 3)
    t3 = t0 + t1 + t2
    return t3

