# @cctt_verify {"v":2,"sym":"sympy.tensor.tensor.riemann_cyclic","kind":"function","src_hash":"d9800b20791e143b","in":{"base":"Any","pred":"isinstance(t2, (TensMul, Tensor))"},"out":{"base":"Any"},"spec":{"lhs":"riemann_cyclic(t2)","rhs":"replace each riemann tensor with an equivalent expression satisfying the cyclic identity","over":{"base":"Any","pred":"isinstance(t2, (TensMul, Tensor))"},"name":"riemann_cyclic_correct"},"guarantee":"replace each riemann tensor with an equivalent expression satisfying the cyclic identity","fibers":[{"name":"(TensMul","pred":"isinstance(t2, (TensMul, Tensor))","path":{"lhs":"riemann_cyclic(x)","rhs":"replace each riemann tensor with an equivalent expression satisfying the cyclic identity","over":{"base":"(TensMul","pred":"isinstance(t2, (TensMul, Tensor))"},"name":"riemann_cyclic_(TensMul_case"},"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.tensor.tensor.riemann_cyclic_(TensMul_correct","statement":"riemann_cyclic satisfies spec on (TensMul inputs"},"trust":"LIBRARY"}],"h1":0,"paths":[],"strategy":"refinement_descent","details":{"exhaustiveness":"z3_proved","n_fibers":1,"h1":0},"assumes":[],"trust":["lean.C4.Descent.descent_soundness","z3.Solver.check"],"compiled":true,"vhash":"d06310c4e3eb0400"}
def riemann_cyclic(t2):
    """
    Replace each Riemann tensor with an equivalent expression
    satisfying the cyclic identity.

    This trick is discussed in the reference guide to Cadabra.

    Examples
    ========

    >>> from sympy.tensor.tensor import TensorIndexType, tensor_indices, TensorHead, riemann_cyclic, TensorSymmetry
    >>> Lorentz = TensorIndexType('Lorentz', dummy_name='L')
    >>> i, j, k, l = tensor_indices('i,j,k,l', Lorentz)
    >>> R = TensorHead('R', [Lorentz]*4, TensorSymmetry.riemann())
    >>> t = R(i,j,k,l)*(R(-i,-j,-k,-l) - 2*R(-i,-k,-j,-l))
    >>> riemann_cyclic(t)
    0
    """
    t2 = t2.expand()
    if isinstance(t2, (TensMul, Tensor)):
        args = [t2]
    else:
        args = t2.args
    a1 = [x.split() for x in args]
    a2 = [[riemann_cyclic_replace(tx) for tx in y] for y in a1]
    a3 = [tensor_mul(*v) for v in a2]
    t3 = TensAdd(*a3).doit(deep=False)
    if not t3:
        return t3
    else:
        return canon_bp(t3)


